import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Determine the actual size needed for the buffer based on user input length
        int bufferSize = Math.min(userInput.length(), 10);

        // Create a char array with dynamic capacity based on user input length
        char[] buffer = new char[bufferSize];

        // Copy user input into the buffer with bounds checking
        userInput.getChars(0, bufferSize, buffer, 0);

        // No risk of buffer overflow as we are using a dynamically sized buffer
    }
}

